local jwt = require "resty.jwt"

local function validate_token(token)
    local key = "your_secret_key"
    local jwt_obj = jwt:verify(key, token)

    if not jwt_obj.verified then
        return false, jwt_obj.reason
    end

    return true, jwt_obj.payload
end

local function has_permission(user_role, required_role)
    return user_role == required_role
end

local uri = ngx.var.uri

if string.match(uri, "/admin") or string.match(uri, "/api") then
    -- Skip permission checks for /admin and /api endpoints
    return
end

local token = ngx.var.cookie_auth_token or ngx.req.get_headers()["Authorization"]

if not token then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.say("No authentication token provided")
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local is_valid, payload = validate_token(token)

if not is_valid then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.say(payload)
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local user_role = payload.role
local required_role = "admin" -- Change this to the required role for your endpoint

if not has_permission(user_role, required_role) then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Insufficient permissions")
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end